// Copyright (c) 2014 Baidu.com, Inc. All rights reserved.
// Use of this source code is governed by a BSD-style license that can be
// found in the LICENSE file.
//
// Author: qinzuoyan01@baidu.com (Qin Zuoyan)

#include <sofa/pbrpc/rpc_error_code.h>

namespace sofa {
namespace pbrpc {

#define MAKE_CASE(name) case name: return (#name)

const char* RpcErrorCodeToString(int error_code)
{
    switch(error_code)
    {
        MAKE_CASE(RPC_SUCCESS);

        MAKE_CASE(RPC_ERROR_PARSE_REQUEST_MESSAGE);
        MAKE_CASE(RPC_ERROR_PARSE_RESPONSE_MESSAGE);
        MAKE_CASE(RPC_ERROR_UNCOMPRESS_MESSAGE);
        MAKE_CASE(RPC_ERROR_COMPRESS_TYPE);
        MAKE_CASE(RPC_ERROR_NOT_SPECIFY_METHOD_NAME);
        MAKE_CASE(RPC_ERROR_PARSE_METHOD_NAME);
        MAKE_CASE(RPC_ERROR_FOUND_SERVICE);
        MAKE_CASE(RPC_ERROR_FOUND_METHOD);
        MAKE_CASE(RPC_ERROR_CHANNEL_BROKEN);
        MAKE_CASE(RPC_ERROR_CONNECTION_CLOSED);
        MAKE_CASE(RPC_ERROR_REQUEST_TIMEOUT);
        MAKE_CASE(RPC_ERROR_REQUEST_CANCELED);
        MAKE_CASE(RPC_ERROR_SERVER_UNAVAILABLE);
        MAKE_CASE(RPC_ERROR_SERVER_UNREACHABLE);
        MAKE_CASE(RPC_ERROR_SERVER_SHUTDOWN);
        MAKE_CASE(RPC_ERROR_SEND_BUFFER_FULL);
        MAKE_CASE(RPC_ERROR_SERIALIZE_REQUEST);
        MAKE_CASE(RPC_ERROR_SERIALIZE_RESPONSE);
        MAKE_CASE(RPC_ERROR_RESOLVE_ADDRESS);
        MAKE_CASE(RPC_ERROR_CREATE_STREAM);
        MAKE_CASE(RPC_ERROR_NOT_IN_RUNNING);
        MAKE_CASE(RPC_ERROR_SERVER_BUSY);

        MAKE_CASE(RPC_ERROR_TOO_MANY_OPEN_FILES);

        MAKE_CASE(RPC_ERROR_UNKNOWN);
        MAKE_CASE(RPC_ERROR_FROM_USER);
    }
    return "RPC_ERROR_UNDEFINED";
}

} // namespace pbrpc
} // namespace sofa

/* vim: set ts=4 sw=4 sts=4 tw=100 */

// Copyright (c) 2014 Baidu.com, Inc. All rights reserved.
// Use of this source code is governed by a BSD-style license that can be
// found in the LICENSE file.
//
// Author: qinzuoyan01@baidu.com (Qin Zuoyan)

#ifndef _SOFA_PBRPC_RPC_ERROR_CODE_H_
#define _SOFA_PBRPC_RPC_ERROR_CODE_H_

namespace sofa {
namespace pbrpc {

enum RpcErrorCode {
    RPC_SUCCESS = 0,
    RPC_ERROR_PARSE_REQUEST_MESSAGE = 1,
    RPC_ERROR_PARSE_RESPONSE_MESSAGE = 2,
    RPC_ERROR_UNCOMPRESS_MESSAGE = 3,
    RPC_ERROR_COMPRESS_TYPE = 4,
    RPC_ERROR_NOT_SPECIFY_METHOD_NAME = 5,
    RPC_ERROR_PARSE_METHOD_NAME = 6,
    RPC_ERROR_FOUND_SERVICE = 7,
    RPC_ERROR_FOUND_METHOD = 8,
    RPC_ERROR_CHANNEL_BROKEN = 9,
    RPC_ERROR_CONNECTION_CLOSED = 10,
    RPC_ERROR_REQUEST_TIMEOUT = 11, // request timeout
    RPC_ERROR_REQUEST_CANCELED = 12, // request canceled
    RPC_ERROR_SERVER_UNAVAILABLE = 13, // server un-healthy
    RPC_ERROR_SERVER_UNREACHABLE = 14, // server un-reachable
    RPC_ERROR_SERVER_SHUTDOWN = 15,
    RPC_ERROR_SEND_BUFFER_FULL = 16,
    RPC_ERROR_SERIALIZE_REQUEST = 17,
    RPC_ERROR_SERIALIZE_RESPONSE = 18,
    RPC_ERROR_RESOLVE_ADDRESS = 19,
    RPC_ERROR_CREATE_STREAM = 20,
    RPC_ERROR_NOT_IN_RUNNING = 21,
    RPC_ERROR_SERVER_BUSY = 22,

    // error code for listener
    RPC_ERROR_TOO_MANY_OPEN_FILES = 101,

    RPC_ERROR_UNKNOWN = 999,
    RPC_ERROR_FROM_USER = 1000,
}; // enum RpcErrorCode

// Convert rpc error code to human readable string.
const char* RpcErrorCodeToString(int error_code);

} // namespace pbrpc
} // namespace sofa

#endif // _SOFA_PBRPC_RPC_ERROR_CODE_H_

